create table inferences
(
    id                bigint unsigned auto_increment
        primary key,
    created_at        datetime(3)                     null,
    updated_at        datetime(3)                     null,
    deleted_at        datetime(3)                     null,
    display_name      varchar(63)                     not null comment '展示名称',
    instance_name     varchar(100)                    not null comment '实例名称',
    user_id           bigint unsigned                 not null comment '用户ID',
    namespace         varchar(63)  default 'default'  not null comment '命名空间',
    cluster_id        bigint unsigned                 not null comment '集群ID',
    deploy_type       varchar(20)                     not null comment '部署类型(DISTRIBUTED/STANDALONE)',
    framework         varchar(20)                     not null comment '推理框架(SGLANG/VLLM)',
    model_pvc_id      bigint unsigned                 not null comment '模型PVC ID',
    image_id          bigint unsigned                 not null comment '镜像ID',
    tensor_parallel   bigint       default 1          null comment '张量并行度',
    pipeline_parallel bigint       default 1          null comment '流水线并行度',
    worker_count      bigint       default 0          null comment 'Worker数量',
    product_id        bigint unsigned                 null comment '产品ID',
    cpu               bigint                          null comment 'CPU配置',
    memory            bigint                          null comment '内存配置(GiB)',
    gpu               bigint                          null comment '单节点GPU数量',
    gpu_model         varchar(191)                    null comment 'GPU型号',
    v_gpu_number      bigint       default 0          null comment 'vGPU数量',
    v_gpu_memory      bigint       default 0          null comment 'vGPU显存 (GB)',
    v_gpu_cores       bigint       default 0          null comment 'vGPU核心数',
    service_port      bigint       default 30000      null comment '服务端口',
    auto_restart      tinyint(1)   default 0          null comment '是否允许自动重启',
    restart_count     bigint       default 0          null comment '已重启次数',
    max_restarts      bigint       default 3          null comment '最大重启次数',
    auth_type         bigint       default 1          null comment '认证类型 1-Authorization 2-API-Key',
    status            varchar(50)  default 'CREATING' not null comment '状态',
    error_msg         text                            null comment '错误信息',
    k8s_resource_uid  varchar(128)                    null comment 'K8s资源UID',
    k8s_resource_name varchar(128)                    null comment 'K8s资源名称',
    started_at        datetime(3)                     null comment '启动时间',
    pay_type          bigint       default 1          null comment '付费类型(1-按量 2-包日 3-包周 4-包月)',
    price             decimal(10, 4)                  null comment '单价',
    order_id          bigint unsigned                 null comment '关联订单ID',
    command           text                            null comment '启动命令(原始字符串)',
    args              text                            null comment '启动参数(JSON格式)',
    model_mount_path  varchar(256) default '/model'   null comment 'PVC挂载路径',
    constraint idx_inferences_instance_name
        unique (instance_name)
);

create index idx_inferences_cluster_id
    on inferences (cluster_id);

create index idx_inferences_deleted_at
    on inferences (deleted_at);

create index idx_inferences_k8s_resource_uid
    on inferences (k8s_resource_uid);

create index idx_inferences_status
    on inferences (status);

create index idx_inferences_user_id
    on inferences (user_id);

