INSERT INTO aiInfra.inferences (id, created_at, updated_at, deleted_at, display_name, instance_name, user_id, namespace, cluster_id, deploy_type, framework, model_pvc_id, image_id, tensor_parallel, pipeline_parallel, worker_count, product_id, cpu, memory, gpu, gpu_model, v_gpu_number, v_gpu_memory, v_gpu_cores, service_port, auto_restart, restart_count, max_restarts, auth_type, status, error_msg, k8s_resource_uid, k8s_resource_name, started_at, pay_type, price, order_id, command, args, model_mount_path) VALUES (25, '2026-02-24 14:28:40.052', '2026-02-24 14:31:21.785', '2026-02-24 14:31:28.260', '2', 'inference-876d96', 1, 'hmz', 1, 'STANDALONE', '', 2, 21, 1, 1, 0, 7, 4, 4, 0, '', 0, 0, 0, 30000, 0, 0, 3, 2, 'STOPPED', '', '40eb94de-864e-4558-bf17-562a23442a71', null, null, 1, 1.0000, 29, '["/bin/sh"]', '["-c","\\"pip","install","--upgrade","transformers","\\u0026\\u0026","python3","-c","\\\\\\"import","torch;","from","transformers","import","AutoModelForCausalLM,","AutoTokenizer;","model_id=\'/2/model/Qwen2.5-0.5B-Instruct\';","print(\'正在加载模型...\');","tokenizer","=","AutoTokenizer.from_pretrained(model_id);","model","=","AutoModelForCausalLM.from_pretrained(model_id,","torch_dtype=torch.float32).to(\'cpu\');","print(\'模型加载成功！开始推理...\');","inputs","=","tokenizer(\'你好，请用一句话介绍你自己。\',","return_tensors=\'pt\').to(\'cpu\');","outputs","=","model.generate(**inputs,","max_new_tokens=50);","print(\'推理结果：\');","print(tokenizer.decode(outputs[0],","skip_special_tokens=True));","import","time;","time.sleep(3600)\\\\\\"\\""]', '/2');
