INSERT INTO aiInfra.inferences (id, created_at, updated_at, deleted_at, display_name, instance_name, user_id, namespace, cluster_id, deploy_type, framework, model_pvc_id, image_id, tensor_parallel, pipeline_parallel, worker_count, product_id, cpu, memory, gpu, gpu_model, v_gpu_number, v_gpu_memory, v_gpu_cores, service_port, auto_restart, restart_count, max_restarts, auth_type, status, error_msg, k8s_resource_uid, k8s_resource_name, started_at, pay_type, price, order_id, command, args, model_mount_path) VALUES (27, '2026-02-24 15:04:00.561', '2026-02-24 15:05:42.266', '2026-02-24 15:05:44.478', '2', 'inference-63cf5b', 1, 'hmz', 1, 'STANDALONE', '', 2, 21, 1, 1, 0, 7, 4, 4, 0, '', 0, 0, 0, 30000, 0, 0, 3, 2, 'STOPPED', '', '89342d0d-0a71-48b9-aa84-af22b6aea5a3', null, null, 1, 1.0000, 31, 'pip install flask transformers torch && echo \'from flask import Flask, request, jsonify; import torch; from transformers import AutoTokenizer, AutoModelForCausalLM; app = Flask(__name__); print(\\"Load Model...\\"); model_id=\\"/2/model/Qwen2.5-0.5B-Instruct\\"; tokenizer = AutoTokenizer.from_pretrained(model_id); model = AutoModelForCausalLM.from_pretrained(model_id, torch_dtype=torch.float32).to(\\"cpu\\"); print(\\"Ready!\\"); @app.route(\\"/v1/chat/completions\\", methods=[\\"POST\\"]) \\ndef chat(): \\n data = request.json; \\n msg = data[\\"messages\\"][-1][\\"content\\"]; \\n inputs = tokenizer(msg, return_tensors=\\"pt\\").to(\\"cpu\\"); \\n outputs = model.generate(**inputs, max_new_tokens=100); \\n res = tokenizer.decode(outputs[0], skip_special_tokens=True); \\n return jsonify({\\"choices\\": [{\\"message\\": {\\"content\\": res}}]}); \\nif __name__ == \\"__main__\\": \\n app.run(host=\\"0.0.0.0\\", port=30000)\' > server.py && python3 server.py"', '', '/2');
